// ─────────────────────────────────────────────────────────────
// Parse form input and prepare research parameters
// ─────────────────────────────────────────────────────────────
const form = $input.first().json;

const topic = (form['Topic I Want to Learn'] || '').trim();
const level = (form['My Current Knowledge Level'] || 'Complete Beginner').trim();
const specificQ = (form['What I Specifically Want to Understand'] || '').trim();
const email = (form['Notification Email'] || '').trim();

if (!topic) throw new Error('Topic is required.');
if (!email) throw new Error('Notification email is required.');

const levelContext = {
  'Complete Beginner': 'Explain from absolute scratch. Use simple analogies. Assume zero prior knowledge.',
  'Some Basics': 'Assume basic understanding. Focus on how things work and practical applications.',
  'Intermediate': 'Skip the basics. Go deeper into architecture, trade-offs, and implementation details.',
  'Advanced - Deep Dive Only': 'Expert level. Focus on cutting-edge developments, research papers, advanced techniques, and edge cases.'
};

return [{ json: {
  topic,
  level,
  levelInstruction: levelContext[level] || levelContext['Complete Beginner'],
  specificQuestions: specificQ,
  email,
  timestamp: new Date().toISOString()
}}];

