// ─────────────────────────────────────────────────────────────
// Parse AI search queries and prepare YouTube + Web searches
// ─────────────────────────────────────────────────────────────
const aiResp = $input.first().json;
const formData = $('\ud83d\udd27 Parse Learning Request').first().json;

let queries = {};
try {
  const raw = aiResp?.message?.content || '{}';
  const cleaned = raw.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  queries = JSON.parse(cleaned);
} catch (e) {
  // Fallback queries
  queries = {
    youtube_queries: [
      `${formData.topic} explained for beginners`,
      `${formData.topic} tutorial 2025 2026`,
      `${formData.topic} how it works`,
      `what is ${formData.topic}`,
      `${formData.topic} practical examples`
    ],
    web_queries: [
      `${formData.topic} complete guide`,
      `${formData.topic} explained simply`,
      `${formData.topic} best practices 2026`
    ],
    topic_summary_prompt: `A comprehensive overview of ${formData.topic}.`
  };
}

return [{ json: {
  ...formData,
  youtubeQueries: queries.youtube_queries || [],
  webQueries: queries.web_queries || [],
  topicSummary: queries.topic_summary_prompt || ''
}}];

// ─────────────────────────────────────────────────────────────
// Extract YouTube video details into clean format
// ─────────────────────────────────────────────────────────────
const resp = $input.first().json;
const formData = $('\ud83d\udd00 Parse Search Queries').first().json;
const items = resp.items || [];

const videos = items.map((item, idx) => {
  const snippet = item.snippet || {};
  const videoId = item.id?.videoId || '';
  return {
    index: idx + 1,
    title: snippet.title || 'Untitled',
    channel: snippet.channelTitle || 'Unknown',
    description: (snippet.description || '').slice(0, 300),
    url: `https://www.youtube.com/watch?v=${videoId}`,
    publishedAt: snippet.publishedAt || '',
    thumbnail: snippet.thumbnails?.high?.url || ''
  };
}).filter(v => v.url.includes('watch?v='));

return [{ json: {
  ...formData,
  youtubeVideos: videos,
  youtubeCount: videos.length
}}];

// ─────────────────────────────────────────────────────────────
// Prepare the master document content for Google Doc creation
// ─────────────────────────────────────────────────────────────
const aiResp = $input.first().json;
const formData = $('\ud83d\udcca Extract Video Details').first().json;

const masterContent = aiResp?.message?.content || aiResp?.choices?.[0]?.message?.content || 'Content generation failed.';

// Build the final document with header and metadata
const now = new Date();
const dateStr = now.toLocaleDateString('en-IN', { year:'numeric', month:'long', day:'numeric' });

const finalDoc = `LEARNING KIT: ${formData.topic.toUpperCase()}
Generated: ${dateStr}
Level: ${formData.level}
Custom Focus: ${formData.specificQuestions || 'General overview'}

${'='.repeat(60)}

${masterContent}

${'='.repeat(60)}

YOUTUBE VIDEOS FOR NOTEBOOKLM
(Copy these URLs into NotebookLM as sources for audio lectures)

${formData.youtubeVideos.map((v, i) => `${i+1}. ${v.title}\n   Channel: ${v.channel}\n   URL: ${v.url}`).join('\n\n')}

${'='.repeat(60)}

NEXT STEPS:
1. Open notebooklm.google.com
2. Create a new notebook titled "${formData.topic}"
3. Add THIS Google Doc as a source (it is already in your Google Drive)
4. Add the YouTube URLs listed above as additional sources
5. Click Audio Overview > Deep Dive > Generate
6. While it generates, also create: Study Guide, FAQ, Quiz
7. Listen to the podcast while walking, commuting, or cooking
8. Use the interactive chat to ask follow-up questions

Your complete learning kit is ready. Learn anywhere, anytime.`;

const docTitle = `Learning Kit: ${formData.topic} (${dateStr})`;

return [{ json: {
  ...formData,
  masterContent: finalDoc,
  docTitle,
  plainContent: masterContent
}}];
